## Steps to Reproduce

1. Run `flutter create flutter_sandbox`.
2. Update the files as follows: 
Add `intl` to dependencies of `pubspec.yaml`
Copy/paste the following into `main.dart`:


<details>
<summary>code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:intl/intl.dart';

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      home: MyHomePage(),
    );
  }
}

class MyHomePage extends StatefulWidget {
  @override
  _MyHomePageState createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  final myTextController = TextEditingController();
  final decimalNumberTextInputFormatter = DecimalNumberTextInputFormatter();

  initState() {
    super.initState();
    myTextController.text = '123,456';
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Gboard bug'),
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: <Widget>[
            Text('After pressing backspace...\n'),
            Text('Cursor is in the wrong location with:'),
            Text('  Gboard keyboard and autofocus: true.\n'),
            Text('Cursor is in the correct location with:'),
            Text('  Microsoft SwiftKey keyboard or autofocus: false.\n'),
            TextFormField(
              controller: myTextController,
              inputFormatters: [
                decimalNumberTextInputFormatter,
              ],
              keyboardType: TextInputType.number,
              autofocus: true,
            ),
          ],
        ),
      ),
    );
  }
}

class DecimalNumberTextInputFormatter extends TextInputFormatter {
  @override
  TextEditingValue formatEditUpdate(TextEditingValue oldValue, TextEditingValue newValue) {
    print('');
    print('oldValue.text:                   ${oldValue.text}');
    print('oldValue.text.length:            ${oldValue.text.length}');
    print('oldValue.selection.start:        ${oldValue.selection.start}');
    print('oldValue.selection.end:          ${oldValue.selection.end}');
    print('oldValue.selection.baseOffset:   ${oldValue.selection.baseOffset}');
    print('oldValue.selection.extentOffset: ${oldValue.selection.extentOffset}');
    print('oldValue.selection.isValid:      ${oldValue.selection.isValid}');
    print('oldValue.selection.isDirectional:${oldValue.selection.isDirectional}');
    print('oldValue.selection.affinity:     ${oldValue.selection.affinity}');
    print('oldValue.composing.start:        ${oldValue.composing.start}');
    print('oldValue.composing.end:          ${oldValue.composing.end}');
    print('oldValue.composing.isValid:      ${oldValue.composing.isValid}');
    print('oldValue.composing.isCollapsed:  ${oldValue.composing.isCollapsed}');
    print('oldValue.composing.isNormalized: ${oldValue.composing.isNormalized}');

    // Check for no change
    if (newValue.text.compareTo(oldValue.text) == 0) {
      return oldValue;
    }

    String newString = _formattedNewValue(oldValue, newValue);

    int cursorLocationFromEnd;
    if (oldValue.selection.end < 0) {
      cursorLocationFromEnd = 0;
    } else {
      cursorLocationFromEnd = oldValue.text.length - oldValue.selection.end;
    }
    final int cursorLocation = newString.length - cursorLocationFromEnd;
    print('new cursor location: $cursorLocation');

    return TextEditingValue(
      text: newString,
      selection: TextSelection.collapsed(
        offset: cursorLocation,
      ),
    );
  }

  String _formattedNewValue(TextEditingValue oldValue, TextEditingValue newValue) {
    String _digitsAndDots = newValue.text.replaceAll(RegExp(r'((?!\d|\.).)*'), '');
    if (_digitsAndDots == '') {
      return '';
    }

    // Remove all non-digits
    final String stripped = _digitsAndDots.replaceAll(RegExp(r'\D'), '');

    // Check for zero
    if (double.tryParse(stripped) == 0.0) {
      return '0';
    }

    final int intNum = int.tryParse(stripped);

    // Check for blank field
    if (intNum == null) {
      return '';
    }

    final currencyFormat = NumberFormat('#,##0', 'en_US');
    final String newString = currencyFormat.format(intNum);

    return newString;
  }
}
```
</details>



